const HOOK_NAME = 'prompt-dispatcher';

/** Maximum total tokens for consolidated output */
const MAX_OUTPUT_TOKENS = 800;

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

type HookFn = (input: HookInput, ctx: HookContext) => HookResult;

interface PromptHookConfig {
  name: string;
  fn: HookFn;
  /** Whether this hook produces context output (vs silent analytics) */
  producesContext: boolean;
  /** If true, this hook runs only once per session (file-based flag tracking) */
  runOnce?: boolean;
}

// -----------------------------------------------------------------------------
// Hook Registry
// -----------------------------------------------------------------------------

/**
 * Registry of 6 UserPromptSubmit hooks managed by this dispatcher.
 *
 * Order matters for context producers — higher priority first.
 * runOnce hooks execute only on the first turn (file-based session flag).
 *
 * profile-injector + memory-context-loader moved to SessionStart (sync-session-dispatcher)
 * where they materialize rules files BEFORE CC loads instructions.
 */
const HOOKS: PromptHookConfig[] = [
  // --- Once-per-session hooks (run on first turn only, file-flag gated) ---
  { name: 'handoff-injector', fn: handoffInjector, producesContext: true, runOnce: true },
  { name: 'agentation-context', fn: agentationContext, producesContext: true, runOnce: true },

  // --- Silent analytics (no context output, fire-and-forget) ---
  { name: 'frustration-detector', fn: frustrationDetector, producesContext: false },
  { name: 'cache-break-detector', fn: cacheBreakDetector, producesContext: false },

  // --- Context producers (output merged into single additionalContext) ---
  { name: 'context-exhaustion-warner', fn: contextExhaustionWarner, producesContext: true },
  { name: 'pipeline-detector', fn: pipelineDetector, producesContext: true },
  // antipattern-warning removed (#972) — now a type:prompt hook in hooks.json
];

/** Exposed for testing */
export const registeredHookNames = () => HOOKS.map(h => h.name);

// -----------------------------------------------------------------------------
// Once-per-session Flag Tracking
// -----------------------------------------------------------------------------

/**
 * Get session directory, preferring CLAUDE_PLUGIN_DATA (CC 2.1.78).
 * Mirrors session-tracker.ts logic so once-flags and events share the same tree.
 */
function getPromptSessionDir(sessionId: string, projectDir: string): string {
  if (process.env.CLAUDE_PLUGIN_DATA) {
    return join(getSessionStorageDir(), sessionId);
  }
  return join(projectDir, '.claude', 'memory', 'sessions', sessionId);
}

/**
 * Check if a once-per-session hook has already run.
 * Uses file-based flags at: {sessionDir}/once-flags/{hook}.done
 */
function hasOnceFlagRun(hookName: string, sessionId: string, projectDir: string): boolean {
  const flagPath = join(getPromptSessionDir(sessionId, projectDir), 'once-flags', `${hookName}.done`);
  return existsSync(flagPath);
}

/**
 * Mark a once-per-session hook as having run.
 */
function setOnceFlagDone(hookName: string, sessionId: string, projectDir: string): void {
  const flagDir = join(getPromptSessionDir(sessionId, projectDir), 'once-flags');
  if (!existsSync(flagDir)) {
    mkdirSync(flagDir, { recursive: true });
  }
  writeFileSync(join(flagDir, `${hookName}.done`), new Date().toISOString(), 'utf8');
}

